const PRICES = {
  'claude-haiku-4-5-20251001': { input: 0.80, output: 4.00 },
  'claude-sonnet-4-6': { input: 3.00, output: 15.00 },
  'claude-opus-4-6': { input: 15.00, output: 75.00 }
};
class CostTracker {
  constructor() { this.calls = []; this.totalCost = 0; }
  add(model, usage) {
    const p = PRICES[model] || PRICES['claude-haiku-4-5-20251001'];
    const cost = (usage.input_tokens / 1e6) * p.input + (usage.output_tokens / 1e6) * p.output;
    this.totalCost += cost;
    this.calls.push({ model, ...usage, cost });
    if (this.totalCost > 1.00) console.warn(`⚠️ High cost alert: $${this.totalCost.toFixed(4)}`);
  }
  summary() { return { calls: this.calls.length, totalCost: this.totalCost.toFixed(6), breakdown: this.calls }; }
}
