class AgentTracer {
  constructor(userId, agentId, goal) {
    this.runId = crypto.randomUUID();
    this.userId = userId; this.agentId = agentId; this.goal = goal;
    this.steps = []; this.totalInputTokens = 0; this.totalOutputTokens = 0;
    this.startedAt = new Date();
  }
  recordLLMCall(model, response) {
    this.totalInputTokens += response.usage.input_tokens;
    this.totalOutputTokens += response.usage.output_tokens;
    this.steps.push({ type: 'llm', model,
      inputTokens: response.usage.input_tokens, outputTokens: response.usage.output_tokens,
      stopReason: response.stop_reason,
      preview: response.content[0]?.text?.slice(0, 200) || '',
      timestamp: new Date() });
  }
  recordToolCall(name, input, output, success) {
    this.steps.push({ type: 'tool', name,
      input: JSON.stringify(input).slice(0, 200),
      output: JSON.stringify(output).slice(0, 200),
      success, timestamp: new Date() });
  }
  async save(outcome) {
    const cost = (this.totalInputTokens / 1e6) * 3 + (this.totalOutputTokens / 1e6) * 15; // sonnet pricing
    await db.agentRun.create({ data: { runId: this.runId, userId: this.userId,
      agentId: this.agentId, goal: this.goal, outcome,
      steps: this.steps, totalInputTokens: this.totalInputTokens,
      totalOutputTokens: this.totalOutputTokens, estimatedCost: cost,
      completedAt: new Date() } });
    console.log(`[${this.runId}] ${outcome} | $${cost.toFixed(4)} | ${this.steps.length} steps`);
  }
}
